{"code": "import json, re
from collections import defaultdict

# Get the file path safely
patents_data_path = locals()['var_functions.query_db:26']

# Load patent data  
with open(patents_data_path, 'r') as f:
    patents = json.load(f)

print(f'Loaded {len(patents)} patents')

# Process patents to extract CPC level 4 codes and count filings
month_map = {
    'january': 1, 'february': 2, 'march': 3, 'april': 4, 'may': 5, 'june': 6,
    'july': 7, 'august': 8, 'september': 9, 'october': 10, 'november': 11, 'december': 12
}

cpc_counts = defaultdict(int)
for patent in patents:
    grant_date = patent['grant_date'].lower()
    if '2019' not in grant_date:
        continue

    month_found = False
    for month_name, month_num in month_map.items():
        if month_name in grant_date and month_num >= 7:
            month_found = True
            break

    if not month_found:
        continue

    if isinstance(patent['cpc'], str) and patent['cpc'].strip().startswith('['):
        try:
            cpc_list = json.loads(patent['cpc'])
            for cpc_entry in cpc_list:
                code = cpc_entry.get('code', '')
                if code and '/' in code:
                    parts = code.split('/')
                    if len(parts) == 2 and len(parts[0]) >= 3 and len(parts[1]) >= 4:
                        section = parts[0][0]
                        class_num = parts[0][1:3]
                        subclass = parts[0][3:] if len(parts[0]) > 3 else ''
                        main_group = parts[1][:4]
                        level4 = f"{section}{class_num}{subclass}/{main_group}"
                        cpc_counts[level4] += 1
        except:
            pass

# Sort by count
top_cpc = sorted(cpc_counts.items(), key=lambda x: x[1], reverse=True)[:10]

print('Top 10 CPC Level 4 groups:')
for code, count in top_cpc:
    print(f'  {code}: {count}')

result = {
    'total_patents': len(patents),
    'unique_cpc_level4': len(cpc_counts),
    'top_groups': [{'code': code, 'count': count} for code, count in top_cpc]
}

print('__RESULT__:')
print(json.dumps(result))"}

{"code": "import json
import re
from math import exp

# Load German patent data
patents_file = 'var_functions.query_db:52'
with open(patents_file, 'r') as f:
    patents = json.load(f)

print(f'Processing {len(patents)} patents with potential German connections')

# Step 1: Parse patents and extract CPC level 4 codes
month_map = {
    'january': 1, 'february': 2, 'march': 3, 'april': 4, 'may': 5, 'june': 6,
    'july': 7, 'august': 8, 'september': 9, 'october': 10, 'november': 11, 'december': 12
}

cpc_yearly = {}  # cpc_level4 -> year -> count

for patent in patents:
    grant_date = patent['grant_date'].lower()

    # Verify 2019 and second half
    if '2019' not in grant_date:
        continue

    month = None
    for month_name, month_num in month_map.items():
        if month_name in grant_date:
            month = month_num
            break

    if month is None or month < 7:
        continue

    # Parse CPC codes
    if isinstance(patent['cpc'], str) and patent['cpc'].strip().startswith('['):
        try:
            cpc_list = json.loads(patent['cpc'])
            for cpc_entry in cpc_list:
                code = cpc_entry.get('code', '')
                if code and '/' in code:
                    parts = code.split('/')
                    if len(parts) == 2 and len(parts[0]) >= 3 and len(parts[1]) >= 4:
                        section = parts[0][0]
                        class_num = parts[0][1:3]
                        subclass = parts[0][3:] if len(parts[0]) > 3 else ''
                        main_group = parts[1][:4]
                        level4_code = f"{section}{class_num}{subclass}/{main_group}"

                        if level4_code not in cpc_yearly:
                            cpc_yearly[level4_code] = {}
                        cpc_yearly[level4_code][2019] = cpc_yearly[level4_code].get(2019, 0) + 1
        except:
            continue

# Step 2: Load CPC titles
cpc_file = 'var_functions.query_db:48'
with open(cpc_file, 'r') as f:
    cpc_defs = json.load(f)

cpc_titles = {item['symbol']: item['titleFull'] for item in cpc_defs}

# Step 3: Calculate EMA and prepare results
alpha = 0.1
results = []

for cpc_code, year_counts in cpc_yearly.items():
    # For each CPC group, calculate EMA with the available years
    years = sorted(year_counts.keys())
    ema_values = {}

    for i, year in enumerate(years):
        count = year_counts[year]
        if i == 0:
            ema = count  # First year, EMA = actual value
        else:
            prev_ema = ema_values[years[i-1]]
            ema = alpha * count + (1 - alpha) * prev_ema
        ema_values[year] = ema

    # Find best year (highest EMA)
    best_year = max(ema_values.keys(), key=lambda y: ema_values[y])

    # Get title for this CPC code (or parent if not found)
    title = cpc_titles.get(cpc_code, '')
    if not title:
        # Try parent codes
        parts = cpc_code.split('/')
        if len(parts) == 2:
            parent = parts[0]
            title = cpc_titles.get(parent, 'Title not available')

    results.append({
        'cpc_group_code': cpc_code,
        'titleFull': title,
        'best_year': best_year,
        'ema_best_year': round(ema_values[best_year], 2),
        'filings_best_year': year_counts[best_year]
    })

# Sort by EMA value (highest first) and take top 10
top_results = sorted(results, key=lambda x: x['ema_best_year'], reverse=True)[:10]

print(f'Found {len(results)} CPC level 4 groups, showing top 10:')
for i, r in enumerate(top_results, 1):
    print(f"{i}. {r['cpc_group_code']}: {r['titleFull'][:60]}...")
    print(f"   Best year: {r['best_year']}, EMA: {r['ema_best_year']}, Filings: {r['filings_best_year']}")

print('__RESULT__:')
print(json.dumps(top_results))"}

